import React, { useState, useEffect } from 'react';
import { Play } from 'lucide-react';
import TrackList from '../components/TrackList';
import { getAllTracks } from '../utils/api';
import { getGenreStyle } from '../utils/helpers';

const GREETING = () => {
  const h = new Date().getHours();
  if (h < 12) return 'Good morning';
  if (h < 18) return 'Good afternoon';
  return 'Good evening';
};

const FEATURED_GENRES = [
  { genre: 'hiphop', label: 'Hip-Hop Hits' },
  { genre: 'pop', label: 'Pop Bangers' },
  { genre: 'jazz', label: 'Jazz Essentials' },
  { genre: 'rock', label: 'Rock Classics' },
  { genre: 'classical', label: 'Classical Focus' },
  { genre: 'reggae', label: 'Reggae Vibes' },
];

export default function Home({ playTrack, toggleLike, isLiked, currentTrack, isPlaying, recentTracks }) {
  const [tracks, setTracks] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getAllTracks()
      .then(d => setTracks(d.tracks || []))
      .finally(() => setLoading(false));
  }, []);

  const featuredTracks = tracks.slice(0, 6);
  const allTracks = tracks.slice(0, 15);

  return (
    <div className="home-page">
      <div className="page-header-gradient" style={{ '--header-color': '#1db954' }}>
        <div className="topbar">
          <div />
          <button className="user-btn">👤 Guest</button>
        </div>
        <h1 style={{ fontSize: 36, fontWeight: 900, marginTop: 16 }}>{GREETING()}</h1>
      </div>

      <div className="page-content">
        {/* Quick Play Grid */}
        <div className="quick-play-grid">
          {FEATURED_GENRES.map(({ genre, label }) => {
            const t = tracks.find(tr => tr.genre === genre);
            const style = getGenreStyle(genre);
            return (
              <div
                key={genre}
                className="quick-play-item"
                onClick={() => t && playTrack(t, tracks.filter(tr => tr.genre === genre))}
              >
                <div className="qp-art" style={{ background: `linear-gradient(135deg, ${style.c1}, ${style.c2})` }}>
                  {style.emoji}
                </div>
                <span className="qp-title">{label}</span>
                <button className="qp-play">
                  <Play size={16} fill="black" />
                </button>
              </div>
            );
          })}
        </div>

        {/* Recently Played */}
        {recentTracks && recentTracks.length > 0 && (
          <section style={{ marginBottom: 40 }}>
            <div className="section-title">Recently Played</div>
            <TrackList
              tracks={recentTracks.slice(0, 5)}
              playTrack={playTrack}
              toggleLike={toggleLike}
              isLiked={isLiked}
              currentTrack={currentTrack}
              isPlaying={isPlaying}
            />
          </section>
        )}

        {/* All Tracks */}
        <section>
          <div className="section-title">All Tracks</div>
          {loading ? (
            <div className="loading-wrap">
              <div className="spinner" />
              <p style={{ color: 'var(--text-subdued)' }}>Loading tracks...</p>
            </div>
          ) : (
            <TrackList
              tracks={allTracks}
              playTrack={playTrack}
              toggleLike={toggleLike}
              isLiked={isLiked}
              currentTrack={currentTrack}
              isPlaying={isPlaying}
            />
          )}
        </section>
      </div>
    </div>
  );
}
